// Lấy output từ node parse JSON
const parsed = $node["Code in JavaScript1"].json.output;
const intent = parsed.intent || "other";
const products = Array.isArray(parsed.products) ? parsed.products : [];

// Lấy kho từ Google Sheets (items hiện tại của node này chính là rows)
const inventoryRows = items.map(i => i.json);

function normalize(s) {
  return String(s || "")
    .toLowerCase()
    .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
    .replace(/đ/g, "d")
    .replace(/\b(kg|g|gr|gram|ml|l|goi|gói|bich|bịch|hop|hộp|lo|lọ|thung|thùng|tai|tải|lang|lạng)\b/g, " ")
    .replace(/[0-9]+([.,][0-9]+)?/g, " ")
    .replace(/[^a-z0-9\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function tokenSet(s) {
  return new Set(normalize(s).split(" ").filter(Boolean));
}

function jaccard(aSet, bSet) {
  const a = [...aSet];
  const inter = a.filter(x => bSet.has(x)).length;
  const union = new Set([...aSet, ...bSet]).size || 1;
  return inter / union;
}

function matchOne(askedRaw, askedQty) {
  const askedNorm = normalize(askedRaw);
  const askedTokens = tokenSet(askedRaw);

  if (!askedNorm) {
    return {
      requested_name: askedRaw,
      asked_qty: Number(askedQty || 0),
      match_found: false,
      reason: "empty_product",
      suggestion: null,
      matched_product: null,
      unit: "",
      stock: 0,
      score: 0,
    };
  }

  const scored = inventoryRows.map(r => {
    const product = String(r.Product || "");
    const productNorm = normalize(product);
    const productTokens = tokenSet(product);

    const contains = (productNorm.includes(askedNorm) || askedNorm.includes(productNorm)) ? 1 : 0;
    const jac = jaccard(askedTokens, productTokens);
    const score = (contains ? 0.8 : 0) + jac;

    const stock = Number(String(r.Count || "0").replace(",", ".")) || 0;

    return { row: r, score, stock };
  });

  scored.sort((a, b) => b.score - a.score);
  const best = scored[0];
  const THRESHOLD = 0.45;

  if (!best || best.score < THRESHOLD) {
    return {
      requested_name: askedRaw,
      asked_qty: Number(askedQty || 0),
      match_found: false,
      reason: "not_found",
      suggestion: best?.row?.Product || null,
      matched_product: null,
      unit: "",
      stock: 0,
      score: best?.score ?? 0,
    };
  }

  return {
    requested_name: askedRaw,
    asked_qty: Number(askedQty || 0),
    match_found: true,
    reason: "",
    suggestion: null,
    matched_product: best.row.Product,
    unit: best.row.Unit || "",
    stock: best.stock,
    score: best.score,
    row_number: best.row.row_number,
  };
}

// Nếu user không nêu sản phẩm mà intent lại là A, ta vẫn trả về items=[]
const results = products.map(p => matchOne(p.name, p.qty));

// message gốc
const userMessage = $node["Telegram Trigger"].json.message?.text || "";

return [{
  json: {
    intent,
    user_message: userMessage,
    items: results
  }
}];
